import { createStore } from 'vuex'
import { useDark } from "@vueuse/core"

export default createStore({
    state: {
        webService: '/apis/',
        menuToggle: false,
        playlistToggle: false,
        nowPlay: {
            id: "",
            song: "",
            singer: "",
            album: "",
            pic: "",
            mv: 0,
        },
        isDark: false,
    },
    getters: {
    },
    mutations: {
        menuToggle: (state) => {
            state.menuToggle = !state.menuToggle;
        },
        playlistToggle: (state) => {
            state.playlistToggle = !state.playlistToggle;
        },
        play: (state, item) => {
            state.nowPlay = item;
        },
        useDark: (state, val) => {
            state.isDark = val
            useDark().value = state.isDark;
        }
    },
    actions: {
    },
    modules: {

    }
})
