<template>
    <div class="myHeader">
        <el-button
            text
            @click="handler"
            :style="{
				transform: menuToggle ? 'rotate(0)' : 'rotate(180deg)',
			}"
        >
            <el-icon>
                <Expand />
            </el-icon>
        </el-button>
        <el-switch
            v-model="isDark"
            class="mt-2"
            style="margin-left: 24px"
            inline-prompt
            :active-icon="Moon"
            :inactive-icon="Sunny"
        />
    </div>
</template>

<script setup>
import { Sunny, Moon } from "@element-plus/icons-vue";
import { computed, ref, watch } from "vue";
import { useStore } from "vuex";

const store = useStore();

const menuToggle = computed(() => {
    return store.state.menuToggle;
});
const handler = () => {
    store.commit("menuToggle");
};

const isDark = ref(false);
watch(
    () => store.state.isDark,
    val => {
        isDark.value = val;
        console.log(val);
    },
    {
        immediate: true
    }
);

watch(isDark, val => {
    store.commit("useDark", val);
});
</script>

<style lang="less" scoped>
.myHeader {
    display: flex;
    flex: 1;
    justify-content: space-between;
    .el-button {
        font-size: 22px;
    }
}
</style>
