<template>
    <div>
        <el-menu router :collapse="menuToggle" default-active="/">
            <img src="@/assets/Spectre_logo_blue.svg" />
            <div v-for="(item, index) in menus" :key="index">
                <el-tooltip :content="item.name" placement="right" :disabled="!menuToggle">
                    <el-menu-item :index="item.path">
                        <i :class="item.meta.icon" style="font-size: 22px"></i>
                        <span>{{ item.name }}</span>
                    </el-menu-item>
                </el-tooltip>
            </div>
        </el-menu>
    </div>
</template>

<script setup>
import menus from "@/router/menu.js";
import { computed, ref, watch, onMounted } from "vue";
import { useStore } from "vuex";

const store = useStore();

const menuToggle = computed(() => {
    return store.state.menuToggle;
});

onMounted(() => {
    window.onresize = () => {
        store.state.menuToggle = document.body.offsetWidth <= 768;
    };
});
</script>

<style lang="less" scoped>
.el-menu {
    overflow: hidden;
    height: 100vh;
    border: none;
    @media (max-width: 768px) {
        height: 95vh !important;
    }
    img {
        width: 130px;
        padding: 12px 30px;
    }
    .el-menu-item {
        letter-spacing: 8px;
        text-indent: 5px;
        font-size: 16px;
        text-shadow: 1.5px 1.5px 1px #ccc;
        transition: 0.3s;
        &.is-active {
            background: var(--el-color-primary-light-9);
            border-right: 6px solid var(--el-menu-active-color);
            margin-right: -1px;
        }
        &:hover {
            background: var(--el-color-primary-light-8);
        }
        &:active {
            background: var(--el-color-primary-light-7);
            transform: scale(0.9);
        }
        span {
            padding-left: 5px;
        }
    }
}
</style>
